#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        unsigned long long X = 0ULL;
        unsigned long long *arr = (unsigned long long*)malloc(N * sizeof(unsigned long long));
        for (int i = 0; i < N; ++i) {
            scanf("%llu", &arr[i]);
            X ^= arr[i];
        }
        if (X == 0ULL) {
            printf("0\n");
            free(arr);
            continue;
        }
        unsigned long long best = ULLONG_MAX;
        for (int i = 0; i < N; ++i) {
            unsigned long long target = X ^ arr[i];
            unsigned long long diff;
            if (target >= arr[i]) diff = target - arr[i];
            else diff = arr[i] - target;
            if (diff < best) best = diff;
        }
        printf("%llu\n", best);
        free(arr);
    }
    return 0;
}

