    while(T--){
        int N; cin>>N;
        unsigned long long X=0, val;
        vector<unsigned long long> a(N);
        for(int i=0;i<N;++i){
            cin>>val; a[i]=val; X ^= val;
        }
        if(X==0){
            cout<<0<<"\n";
            continue;
        }
        unsigned long long ans = ULLONG_MAX;
        for(auto v: a){
            unsigned long long target = X ^ v;
            unsigned long long diff = (target>v)? target-v : v-target;
            ans = min(ans, diff);
        }
        cout<<ans<<"\n";
    }
    return 0;
}

