for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  let arr = new Array(N);
  let X = 0;
  for (let i = 0; i < N; ++i) {
    const val = Number(input[idx++]);
    arr[i] = val;
    X ^= val;
  }
  if (X === 0) {
    outputs.push('0');
    continue;
  }
  let best = Number.MAX_SAFE_INTEGER;
  for (let v of arr) {
    const target = X ^ v;
    const diff = Math.abs(target - v);
    if (diff < best) best = diff;
  }
  outputs.push(String(best));
}
